```class ExamRoom {

    private int n;
    private int[] seats;
    private int nextSeat;

    public ExamRoom(int n) {
        this.n = n;
        this.seats = new int[n];
        this.nextSeat = -1;
    }

    public int seat() {
        int maxDist = 0;
        int seat = 0;
        for (int i = 0; i < n; i++) {
            if (seats[i] == 0) {
                int dist = i > 0 ? i : n - i - 1;
                if (dist > maxDist) {
                    maxDist = dist;
                    seat = i;
                }
            }
        }
        seats[seat] = 1;
        nextSeat = seat;
        return seat;
    }

    public void leave(int p) {
        seats[p] = 0;
        if (p > 0 && seats[p - 1] == 1) {
            seats[p - 1] = 0;
            nextSeat = p - 1;
        } else if (p < n - 1 && seats[p + 1] == 1) {
            seats[p + 1] = 0;
            nextSeat = p + 1;
        }
    }
}
```
